module dvfs_controller(  
    input [2:0] voltage,  
    output reg [1:0] obf_frequency  
);  
    always @(*) begin  
        case (voltage)  
            3'b000: obf_frequency = 2'b00;  
            3'b001: obf_frequency = 2'b01;  
            3'b010: obf_frequency = 2'b10;  
            3'b011, 3'b100: obf_frequency = 2'b11;  
            3'b101, 3'b110: obf_frequency = 2'b11;  
            3'b111: obf_frequency = 2'b00;  
            default: obf_frequency = 2'b00;  
        endcase  
    end  
endmodule
